/** Strip markdown formatting for cleaner speech */
export function stripMarkdown(text: string): string {
  return (
    text
      // Remove code blocks
      .replace(/```[\s\S]*?```/g, match => {
        return match.replace(/```\w*\n?/g, "").trim();
      })
      // Remove inline code backticks
      .replace(/`([^`]+)`/g, "$1")
      // Remove bold/italic markers
      .replace(/\*{1,3}([^*]+)\*{1,3}/g, "$1")
      .replace(/_{1,3}([^_]+)_{1,3}/g, "$1")
      // Remove strikethrough
      .replace(/~~([^~]+)~~/g, "$1")
      // Remove links, keep text
      .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
      // Remove headers markers
      .replace(/^#{1,6}\s+/gm, "")
      // Remove horizontal rules
      .replace(/^---+$/gm, "")
      // Remove list markers
      .replace(/^\s*[-*+]\s+/gm, "")
      .replace(/^\s*\d+\.\s+/gm, "")
      // Collapse multiple whitespace
      .replace(/\n{2,}/g, "\n\n")
      .trim()
  );
}

/** Split text into chunks at sentence boundaries, each ≤ maxChars */
export function chunkBySentences(text: string, maxChars: number): string[] {
  const chunks: string[] = [];
  let current = "";

  // Split on sentence boundaries (., !, ?, followed by space or end)
  const sentences = text.split(/(?<=[.!?])\s+/);

  for (const sentence of sentences) {
    if (current.length === 0) {
      current = sentence;
    } else if (current.length + 1 + sentence.length <= maxChars) {
      current += " " + sentence;
    } else {
      chunks.push(current);
      current = sentence;
    }
  }

  if (current.length > 0) {
    chunks.push(current);
  }

  // If a single chunk exceeds maxChars (no sentence boundaries), hard-split at maxChars
  const result: string[] = [];
  for (const chunk of chunks) {
    if (chunk.length <= maxChars) {
      result.push(chunk);
    } else {
      // Hard split at word boundaries
      let remaining = chunk;
      while (remaining.length > 0) {
        if (remaining.length <= maxChars) {
          result.push(remaining);
          break;
        }
        let splitAt = remaining.lastIndexOf(" ", maxChars);
        if (splitAt === -1) splitAt = maxChars;
        result.push(remaining.slice(0, splitAt));
        remaining = remaining.slice(splitAt).trim();
      }
    }
  }

  return result;
}

/** Generate a one-line summary for notifications */
export function summarize(text: string, maxLen = 80): string {
  const firstLine = text.split("\n")[0] ?? "";
  if (firstLine.length <= maxLen) return firstLine;
  return firstLine.slice(0, maxLen - 1) + "…";
}

/**
 * Platform abstraction for pi-speak extension.
 *
 * All OS-specific calls are isolated behind the Platform interface
 * so Linux and Windows implementations can be dropped in later.
 */

import { execSync, spawn, type ChildProcess } from "node:child_process";
import { debug, debugError } from "./debug";

export interface Platform {
  /** Play an MP3 file. Resolves when playback finishes. */
  playAudio(filePath: string, onProcess?: (proc: ChildProcess) => void): Promise<void>;
  /** Whether this platform is supported */
  readonly supported: boolean;
  /** Whether this platform output is muted */
  readonly isMuted: boolean;
}

/**
 * Check if macOS output is muted using AppleScript.
 * Returns true if muted, false otherwise.
 */
export function isMacMuted(): boolean {
  try {
    const volumeOutput = execSync('osascript -e "output volume of (get volume settings)"', {
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"]
    }).trim();
    const volume = parseInt(volumeOutput, 10);

    const mutedOutput = execSync('osascript -e "output muted of (get volume settings)"', {
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"]
    }).trim();

    debug(`isMacMuted: volume=${volume} muted=${mutedOutput}`);
    return volume === 0 || mutedOutput === "true";
  } catch (err) {
    debug(`isMacMuted: failed to check — ${err instanceof Error ? err.message : String(err)}`);
    return false;
  }
}

/** Check if the current platform is supported */
export function isPlatformSupported(): boolean {
  return process.platform === "darwin";
}

export function createPlatform(): Platform {
  const muted = isMacMuted();

  switch (process.platform) {
    case "darwin":
      return createMacOSPlatform(muted);
    default:
      return {
        playAudio: async () => {
          debug(`playAudio: platform "${process.platform}" is not supported — no audio playback`);
        },
        supported: false,
        isMuted: false
      };
  }
}

function createMacOSPlatform(isMuted: boolean): Platform {
  return {
    supported: true,
    isMuted,
    async playAudio(filePath, onProcess) {
      if (isMuted) {
        debug(`playAudio: skipped — system is muted`);
        return;
      }

      debug(`playAudio: ${filePath}`);
      return new Promise<void>((resolve, reject) => {
        const proc = spawn("afplay", [filePath], { stdio: "ignore" });
        debug(`playAudio: afplay pid=${proc.pid}`);
        if (onProcess) onProcess(proc);
        proc.on("close", code => {
          debug(`playAudio: afplay pid=${proc.pid} exited with code=${code}`);
          if (code === 0 || code === null) resolve();
          else reject(new Error(`afplay exited with code ${code}`));
        });
        proc.on("error", err => {
          debugError(`playAudio: afplay pid=${proc.pid} error`, err);
          reject(err);
        });
      });
    }
  };
}

/**
 * Debug logger for pi-speak extension.
 *
 * Writes timestamped messages to the log file specified in config.
 * Can be disabled by setting PI_SPEAK_DEBUG=0 in the environment.
 */

import { appendFileSync, existsSync, statSync, truncateSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";

/** Default debug log path */
const DEFAULT_LOG_PATH = join(homedir(), ".pi-speak-debug.log");
/** Default max log size in bytes (2 MB) */
const DEFAULT_LOG_MAX_BYTES = 2 * 1024 * 1024;

let _logPath = DEFAULT_LOG_PATH;
let _maxLogBytes = DEFAULT_LOG_MAX_BYTES;
let _enabled = process.env.PI_SPEAK_DEBUG !== "0";

/** Configure debug logger from config */
export function configureDebug(config: { enabled: boolean; logPath: string; logMaxBytes: number }): void {
  _enabled = config.enabled;
  _logPath = config.logPath.startsWith("~") ? join(homedir(), config.logPath.slice(1)) : config.logPath;
  _maxLogBytes = config.logMaxBytes;
}

/** Set debug logging enabled/disabled (e.g., from config.debug) */
export function setDebugEnabled(enabled: boolean): void {
  _enabled = enabled;
}

/** Rotate log if it exceeds max size */
function maybeRotate(): void {
  try {
    if (!existsSync(_logPath)) return;
    const stat = statSync(_logPath);
    if (stat.size >= _maxLogBytes) {
      truncateSync(_logPath, 0);
    }
  } catch (err) {
    console.warn(`[pi-speak] debug: failed to rotate log: ${err instanceof Error ? err.message : String(err)}`);
  }
}

export function debug(msg: string): void {
  if (!_enabled) return;
  maybeRotate();
  const ts = new Date().toISOString();
  try {
    appendFileSync(_logPath, `[${ts}] ${msg}\n`);
  } catch (err) {
    // Fallback to console when file logging fails
    console.log(`[pi-speak] ${msg}`);
    console.warn(`[pi-speak] debug: failed to write to log file: ${err instanceof Error ? err.message : String(err)}`);
  }
}

/** Log an error with full stack trace */
export function debugError(msg: string, err: unknown): void {
  if (!_enabled) return;
  const detail = err instanceof Error ? `${err.message}\n${err.stack ?? ""}` : String(err);
  debug(`${msg}: ${detail}`);
}

