    "openRouterKey": null
  }
}
```

```ts
export interface SpeakConfig {
  $schema: string;
  version: number;

  // https://docs.v8.unrealspeech.com/
  tts: {
    voiceId: string;
    bitrate: string;
    speed: number;
    pitch: number;
    maxChunkChars: number;
  };

  behavior: {
    shortcut: string;
    pingEnabled: boolean;
    pingOnStartEnabled: boolean;
    fallbackPingText: string;
  };

  // https://openrouter.ai/models
  summarizer: {
    enabled: boolean;
    model: string;
    maxTokens: number;
    timeoutMs: number;
  };

  debug: {
    enabled: boolean;
    logPath: string;
    logMaxBytes: number;
  };

  api: {
    unrealSpeechKey: string | null;
    openRouterKey: string | null;
  };
}
```

**Rationale for additions/nesting:**
- `behavior.pingEnabled` — users may want readback of full text only, not a ping
- `behavior.fallbackPingText` — users can customize the "Work finished" message
- `summarizer.enabled` — avoids requiring OpenRouter key; fallback-only mode is valid
- `summarizer.maxTokens`, `summarizer.timeoutMs` — previously hardcoded
- `debug.logPath`, `debug.logMaxBytes` — previously hardcoded
- `api.*Key` — optional config-file-based key storage (env vars take precedence)
- `$schema` — enables IDE autocomplete and JSON Schema validation
- `version` — enables future migrations without breaking existing configs

**Documentation links (to include in generated config file comments):**
- TTS voices: https://docs.v8.unrealspeech.com
- Summarizer models: https://openrouter.ai/models

---

## Migration Strategy

```ts
const CURRENT_VERSION = 1;
const SCHEMA_URL = "https://raw.githubusercontent.com/nikbrunner/pi-speak/main/src/config.schema.json";

function migrate(raw: unknown, fromVersion: number): SpeakConfig {
  let cfg = raw as Record<string, unknown>;

  if (fromVersion < 1) {
    // v0 → v1: flat → nested structure
    cfg = {
      $schema: SCHEMA_URL,
      version: 1,
      tts: {
        voiceId: cfg.voiceId ?? "Sierra",
        bitrate: cfg.bitrate ?? "192k",
        speed: cfg.speed ?? 0,
        pitch: cfg.pitch ?? 1.0,
        maxChunkChars: cfg.maxChunkChars ?? 900,
      },
      behavior: {
        shortcut: cfg.shortcut ?? "alt+r",
        pingEnabled: true,
        pingOnStartEnabled: false,
        fallbackPingText: "Work finished.",
      },
      summarizer: {
        enabled: true,
        model: cfg.summarizerModel ?? "openai/gpt-oss-20b",
        maxTokens: 60,
        timeoutMs: 5000,
      },
      debug: {
        enabled: cfg.debug ?? true,
        logPath: "~/.pi-speak-debug.log",
        logMaxBytes: 2 * 1024 * 1024,
      },
      api: {
        unrealSpeechKey: null,
        openRouterKey: null,
      },
    };
  }

  // Future migrations go here:
  // if (fromVersion < 2) { ... }

  return cfg as SpeakConfig;
}
```

