## Testing Script

A `scripts/test-config.mjs` script can be added to automate the manual tests:

```mjs
#!/usr/bin/env node
/**
 * Config validation and migration test script
 * Run with: node scripts/test-config.mjs
 */

import { mkdtempSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";

// Mock CONFIG_PATH for testing
const TEST_DIR = mkdtempSync(join(tmpdir(), "pi-speak-test-"));
const TEST_CONFIG_PATH = join(TEST_DIR, "config.json");

// Override the module's CONFIG_PATH (would need to export it or use proxy)
process.env.PI_SPEAK_TEST_CONFIG_DIR = TEST_DIR;

const tests = [
  {
    name: "v0 migration (flat → nested)",
    setup: () => writeFileSync(TEST_CONFIG_PATH, JSON.stringify({
      voiceId: "Scarlett",
      speed: 0.5
    })),
    check: (config) => {
      const pass = config.version === 1 &&
                   config.tts.voiceId === "Scarlett" &&
                   config.tts.speed === 0.5;
      return { pass, reason: pass ? "" : `Expected v1 with Scarlettspeed=0.5, got ${JSON.stringify(config)}` };
    }
  },
  {
    name: "validation: invalid tts.speed type",
    setup: () => writeFileSync(TEST_CONFIG_PATH, JSON.stringify({
      version: 1,
      tts: { speed: "fast" }
    })),
    check: (config, error) => {
      const pass = error && error.message.includes("tts.speed");
      return { pass, reason: pass ? "" : `Expected Zod error about tts.speed, got ${error?.message}` };
    }
  },
  {
    name: "minimal config (all defaults)",
    setup: () => writeFileSync(TEST_CONFIG_PATH, "{}"),
    check: (config) => {
      const pass = config.version === 1 &&
                   config.tts.voiceId === "Sierra" &&
                   config.summarizer.enabled === true;
      return { pass, reason: pass ? "" : `Expected all defaults, got ${JSON.stringify(config)}` };
    }
  },
  {
    name: "unknown keys warning",
    setup: () => writeFileSync(TEST_CONFIG_PATH, JSON.stringify({
      version: 1,
      tts: { voiceId: "Scarlett" },
      unknownField: true
    })),
    check: (config, error, warnings) => {
      const pass = warnings && warnings.some(w => w.includes("unknownField"));
      return { pass, reason: pass ? "" : "Expected warning about unknownField" };
    }
  }
];

// ... test runner that imports loadConfig and runs each test
```

Add to `package.json`:
```json
{
  "scripts": {
    "test:config": "node scripts/test-config.mjs"
  }
}
```

Run: `npm run test:config`

