import { describe, expect, it } from "vitest";
import { DEFAULT_CONFIG } from "./defaults";
import { CURRENT_VERSION, migrate } from "./migrations";
import { SpeakConfigSchema } from "./schema";

describe("SpeakConfigSchema", () => {
  describe("valid configs", () => {
    // Note: Zod 4 doesn't cascade defaults into empty nested objects.
    // Empty nested objects remain empty after parsing.
    // The loadConfig() in index.ts falls back to DEFAULT_CONFIG when this happens.
    it("should accept minimal config with nested defaults", () => {
      const input = {
        tts: { voiceId: "Scarlett" }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.tts.voiceId).toBe("Scarlett");
        expect(result.data.tts.bitrate).toBe("192k");
        expect(result.data.tts.speed).toBe(0);
      }
    });

    it("should accept partial tts overrides", () => {
      const input = {
        tts: { voiceId: "Scarlett", bitrate: "128k", speed: -0.5 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.tts.voiceId).toBe("Scarlett");
        expect(result.data.tts.bitrate).toBe("128k");
        expect(result.data.tts.speed).toBe(-0.5);
        expect(result.data.tts.pitch).toBe(1.0); // default
      }
    });

    it("should accept full valid config", () => {
      const input = {
        version: 1,
        tts: {
          voiceId: "Scarlett",
          bitrate: "96k",
          speed: -0.5,
          pitch: 0.8,
          maxChunkChars: 500
        },
        behavior: {
          shortcut: "cmd+r",
          pingEnabled: false,
          pingOnStartEnabled: true,
          fallbackPingText: "Done!"
        },
        summarizer: {
          enabled: false,
          model: "anthropic/claude-3",
          maxTokens: 100,
          timeoutMs: 10000
        },
        debug: {
          enabled: false,
          logPath: "/tmp/debug.log",
          logMaxBytes: 1024 * 1024
        },
        api: {
          unrealSpeechKey: "key-123",
          openRouterKey: "key-456"
        }
      };

      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.tts.voiceId).toBe("Scarlett");
        expect(result.data.behavior.shortcut).toBe("cmd+r");
        expect(result.data.behavior.pingEnabled).toBe(false);
        expect(result.data.summarizer.enabled).toBe(false);
        expect(result.data.debug.enabled).toBe(false);
        expect(result.data.api.unrealSpeechKey).toBe("key-123");
      }
    });
  });

  describe("invalid configs", () => {
    it("should reject invalid tts.speed type (string)", () => {
      const input = {
        tts: { speed: "fast" }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.error.issues.some(i => i.path.includes("speed"))).toBe(true);
      }
    });

    it("should reject tts.speed out of range", () => {
      const input = {
        tts: { speed: 5 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
    });

    it("should reject tts.pitch out of range", () => {
      const input = {
        tts: { pitch: 0.1 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
    });

    it("should reject maxChunkChars exceeding limit", () => {
      const input = {
        tts: { maxChunkChars: 1001 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
    });

    it("should reject summarizer.maxTokens too small", () => {
      const input = {
        summarizer: { maxTokens: 0 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
    });

    it("should reject summarizer.timeoutMs too small", () => {
      const input = {
        summarizer: { timeoutMs: 500 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
    });

    it("should reject invalid logMaxBytes", () => {
      const input = {
        debug: { logMaxBytes: 512 }
      };
      const result = SpeakConfigSchema.safeParse(input);

      expect(result.success).toBe(false);
    });
  });

  describe("boundary values", () => {
    it("should accept min tts.speed", () => {
      const result = SpeakConfigSchema.safeParse({
        tts: { speed: -1 }
      });
      expect(result.success).toBe(true);
    });

    it("should accept max tts.speed", () => {
      const result = SpeakConfigSchema.safeParse({
        tts: { speed: 1 }
      });
      expect(result.success).toBe(true);
    });

    it("should accept min tts.pitch", () => {
      const result = SpeakConfigSchema.safeParse({
        tts: { pitch: 0.5 }
      });
      expect(result.success).toBe(true);
    });

    it("should accept max tts.pitch", () => {
      const result = SpeakConfigSchema.safeParse({
        tts: { pitch: 1.5 }
      });
      expect(result.success).toBe(true);
    });

    it("should accept min maxChunkChars", () => {
      const result = SpeakConfigSchema.safeParse({
        tts: { maxChunkChars: 1 }
      });
      expect(result.success).toBe(true);
    });

    it("should accept max maxChunkChars", () => {
      const result = SpeakConfigSchema.safeParse({
        tts: { maxChunkChars: 1000 }
      });
      expect(result.success).toBe(true);
    });
  });
});

describe("migrate", () => {
