      enabled: true,
      model: "openai/gpt-oss-20b",
      maxTokens: 60,
      timeoutMs: 5000,
      ...overrides.summarizer
    },
    debug: {
      enabled: true,
      logPath: "~/.pi-speak-debug.log",
      logMaxBytes: 2097152,
      ...overrides.debug
    },
