  writeFileSync: vi.fn()
}));

// Mock fetch
const mockFetch = vi.fn();
global.fetch = mockFetch;

// Mock tmpdir
vi.mock("node:os", () => ({
  default: { tmpdir: () => "/tmp" },
  tmpdir: () => "/tmp"
}));

// Mock path
vi.mock("node:path", () => ({
  default: { join: (...args: string[]) => args.join("/") },
  join: (...args: string[]) => args.join("/")
}));

describe("TTSPlayer", () => {
  const defaultConfig: SpeakConfig = {
    $schema: "https://example.com/schema",
    version: 1,
    tts: {
      voiceId: "Sierra",
      bitrate: "192k",
      speed: 0,
      pitch: 1.0,
      maxChunkChars: 900
    },
    behavior: {
      shortcut: "alt+r",
      pingEnabled: true,
      pingOnStartEnabled: false,
      fallbackPingText: "Work finished."
    },
    summarizer: {
      enabled: true,
      model: "openai/gpt-oss-20b",
      maxTokens: 60,
      timeoutMs: 5000
    },
    debug: {
      enabled: true,
      logPath: "~/.pi-speak-debug.log",
      logMaxBytes: 2097152
    },
    api: {
      unrealSpeechKey: null,
      openRouterKey: null
    }
  };

  let player: TTSPlayer;

  beforeEach(() => {
    vi.clearAllMocks();
    player = new TTSPlayer(
      {
        supported: true,
        isMuted: false,
        playAudio: vi.fn().mockResolvedValue(undefined)
      },
      defaultConfig
    );
  });

  afterEach(() => {
    player.stop();
  });

  describe("configuration", () => {
    it("should use config voiceId", () => {
      expect(player["config"].voiceId).toBe("Sierra");
    });

    it("should use config bitrate", () => {
      expect(player["config"].bitrate).toBe("192k");
    });

    it("should use config speed", () => {
      expect(player["config"].speed).toBe(0);
    });

    it("should use config pitch", () => {
      expect(player["config"].pitch).toBe(1.0);
    });

    it("should use config shortcut", () => {
      expect(player["shortcutLabel"]).toBe("alt+r");
    });
  });

  describe("playback state", () => {
    it("should not be playing initially", () => {
      expect(player.playing).toBe(false);
    });

    it("should have empty cached files initially", () => {
      expect(player.cachedFiles).toEqual([]);
    });
  });

  describe("clearCache", () => {
    it("should clear cached files", () => {
      player["cachedAudioFiles"] = ["/tmp/test1.mp3", "/tmp/test2.mp3"];
      player.clearCache();
      expect(player.cachedFiles).toEqual([]);
    });
  });

  describe("chunking behavior", () => {
    it("should respect maxChunkChars configuration", () => {
      const customPlayer = new TTSPlayer(
        {
          supported: true,
          isMuted: false,
          playAudio: vi.fn().mockResolvedValue(undefined)
        },
        {
          ...defaultConfig,
          tts: { ...defaultConfig.tts, maxChunkChars: 50 }
        }
      );

      expect(customPlayer["maxChunkChars"]).toBe(50);
    });
  });
});

describe("TTS config defaults", () => {
  it("should have correct default values", () => {
    const player = new TTSPlayer(
      {
        supported: true,
        isMuted: false,
        playAudio: vi.fn().mockResolvedValue(undefined)
      },
      {
        tts: { voiceId: "Sierra", bitrate: "192k", speed: 0, pitch: 1.0, maxChunkChars: 900 },
        behavior: {
